```tsx
"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";
import { LiveList, LiveObject } from "@liveblocks/client";
import { useSelf, useStorage, useMutation } from "@/lib/liveblocks";

type Tool = "pen" | "eraser";

export function CanvasScaffold({ userId }: { userId: string }) {
  const [tool, setTool] = useState<Tool>("pen");
  const [color, setColor] = useState<string>("#000000");
  const [width, setWidth] = useState<number>(4);

  const self = useSelf();
  const currentUserId = self?.id ?? userId;

  // Track active stroke index for drawing
  const activeStrokeIndexRef = useRef<number | null>(null);
  const lastPointTimeRef = useRef<number>(0);
  const isDrawingRef = useRef(false);

  // Get strokes for rendering
  const strokes = useStorage(root => root.strokes);

  // Create a new stroke on pointer down
  const startStroke = useMutation(
    ({ storage }, point: { x: number; y: number }) => {
      const strokes = storage.get("strokes");
      const stroke = new LiveObject({
        id: `stroke-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
        userId: currentUserId,
        color,
        width,
        points: new LiveList([new LiveObject({ x: point.x, y: point.y })]),
      });
      strokes.push(stroke);
      activeStrokeIndexRef.current = strokes.length - 1;
    },
    [currentUserId, color, width]
  );

  // Add a point to the active stroke
  const addPoint = useMutation(
    ({ storage }, point: { x: number; y: number }) => {
      const strokes = storage.get("strokes");
      const idx = activeStrokeIndexRef.current;
      if (idx !== null && idx >= 0 && idx < strokes.length) {
        const stroke = strokes.get(idx);
        if (stroke) {
          const points = stroke.get("points");
          points.push(new LiveObject({ x: point.x, y: point.y }));
        }
      }
    },
    []
  );

  // Finalize stroke on pointer up
  const endStroke = useMutation(
    ({ storage }) => {
      activeStrokeIndexRef.current = null;
    },
    []
  );

  // Eraser: delete a stroke by index
  const deleteStroke = useMutation(
    ({ storage }, index: number) => {
      const strokes = storage.get("strokes");
      strokes.delete(index);
    },
    []
  );

  // Undo: remove the most recent stroke by the current user
  const undoMyLastStroke = useMutation(
    ({ storage }) => {
      const strokes = storage.get("strokes");
      // Iterate from the end to find the most recent stroke by this user
      for (let i = strokes.length - 1; i >= 0; i--) {
        const stroke = strokes.get(i);
        if (stroke.get("userId") === currentUserId) {
          strokes.delete(i);
          return;
        }
      }
    },
    [currentUserId]
  );

  // Pointer event handlers
  const handlePointerDown = useCallback(
    (e: React.PointerEvent<SVGSVGElement>) => {
      if (tool === "eraser") return; // eraser handled differently
      const rect = e.currentTarget.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      isDrawingRef.current = true;
      lastPointTimeRef.current = Date.now();
      startStroke({ x, y });
    },
    [tool, startStroke]
  );

  const handlePointerMove = useCallback(
    (e: React.PointerEvent<SVGSVGElement>) => {
      if (!isDrawingRef.current || tool === "eraser") return;

      const now = Date.now();
      if (now - lastPointTimeRef.current < 30) return;
      lastPointTimeRef.current = now;

      const rect = e.currentTarget.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      addPoint({ x, y });
    },
    [tool, addPoint]
  );

  const handlePointerUp = useCallback(() => {
    if (isDrawingRef.current) {
      isDrawingRef.current = false;
      endStroke();
    }
  }, [endStroke]);

  // Handle eraser click on a polyline
  const handleEraserClick = useCallback(
    (strokeIndex: number) => {
      if (tool === "eraser") {
        deleteStroke(strokeIndex);
      }
    },
    [tool, deleteStroke]
  );

  // Undo handler
  const handleUndo = useCallback(() => {
    undoMyLastStroke();
  }, [undoMyLastStroke]);

  // Render polylines
  const renderStrokes = () => {
    if (!strokes) return null;

    return Array.from({ length: strokes.length }, (_, i) => {
      const stroke = strokes.get(i);
      if (!stroke) return null;

      const id = stroke.get("id");
      const strokeUserId = stroke.get("userId");
      const strokeColor = stroke.get("color");
      const strokeWidth = stroke.get("width");
      const points = stroke.get("points");

      const pointsStr = Array.from({ length: points.length }, (_, j) => {
        const p = points.get(j);
        return `${p.get("x")},${p.get("y")}`;
      }).join(" ");

      return (
        <polyline
          key={id}
          data-stroke-id={id}
          data-user-id={strokeUserId}
          points={pointsStr}
          fill="none"
          stroke={strokeColor}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeLinejoin="round"
          onClick={() => handleEraserClick(i)}
          style={{ cursor: tool === "eraser" ? "pointer" : "default", pointerEvents: tool === "eraser" ? "stroke" : "none" }}
        />
      );
    });
  };

  return (
    <div style={{ padding: 16 }}>
      <h1>Collaborative Drawing</h1>
      <p>
        User: <strong data-testid="current-user">{userId}</strong>
      </p>
      <div style={{ display: "flex", gap: 8, marginBottom: 12, alignItems: "center" }}>
        <label>
          Color
          <input
            data-testid="color-picker"
            type="text"
            value={color}
            onChange={(e) => setColor(e.target.value)}
            style={{ marginLeft: 4, width: 96 }}
          />
        </label>
        <label>
          Width
          <input
            data-testid="width-picker"
            type="number"
            min={1}
            max={32}
            value={width}
            onChange={(e) => setWidth(Number(e.target.value))}
            style={{ marginLeft: 4, width: 64 }}
          />
        </label>
        <button
          data-testid="tool-pen"
          onClick={() => setTool("pen")}
          aria-pressed={tool === "pen"}
        >
          Pen
        </button>
        <button
          data-testid="tool-eraser"
          onClick={() => setTool("eraser")}
          aria-pressed={tool === "eraser"}
        >
          Eraser
        </button>
        <button data-testid="undo-mine" onClick={handleUndo}>
          Undo my last stroke
        </button>
      </div>
      <svg
        data-testid="canvas"
        width={1024}
        height={720}
        viewBox="0 0 1024 720"
        style={{ background: "#fafafa", border: "1px solid #ddd" }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
      >
        {renderStrokes()}
      </svg>
    </div>
  );
}
```

