```tsx
"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";
import { LiveList, LiveObject } from "@liveblocks/client";
import { useSelf, useStorage, useMutation } from "@/lib/liveblocks";

type Tool = "pen" | "eraser";

export function CanvasScaffold({ userId }: { userId: string }) {
  const [tool, setTool] = useState<Tool>("pen");
  const [color, setColor] = useState<string>("#000000");
  const [width, setWidth] = useState<number>(4);

  const self = useSelf();
  const currentUserId = self?.id ?? userId;

  const activeStrokeIdRef = useRef<string | null>(null);
  const isDrawingRef = useRef(false);
  const lastPointTimeRef = useRef(0);

  const strokes = useStorage(root => root.strokes);

  const startStroke = useMutation(
    ({ storage }, point: { x: number; y: number }, strokeId: string) => {
      const strokes = storage.get("strokes");
      const stroke = new LiveObject({
        id: strokeId,
        userId: currentUserId,
        color,
        width,
        points: new LiveList([new LiveObject({ x: point.x, y: point.y })]),
      });
      strokes.push(stroke);
    },
    [currentUserId, color, width]
  );

  const addPoint = useMutation(
    ({ storage }, point: { x: number; y: number }, strokeId: string) => {
      const strokes = storage.get("strokes");
      for (let i = 0; i < strokes.length; i++) {
        const stroke = strokes.get(i);
        if (stroke.get("id") === strokeId) {
          const points = stroke.get("points");
          points.push(new LiveObject({ x: point.x, y: point.y }));
          return;
        }
      }
    },
    []
  );

  const deleteStrokeById = useMutation(
    ({ storage }, strokeId: string) => {
      const strokes = storage.get("strokes");
      for (let i = 0; i < strokes.length; i++) {
        if (strokes.get(i).get("id") === strokeId) {
          strokes.delete(i);
          return;
        }
      }
    },
    []
  );

  const undoMyLastStroke = useMutation(
    ({ storage }) => {
      const strokes = storage.get("strokes");
      for (let i = strokes.length - 1; i >= 0; i--) {
        if (strokes.get(i).get("userId") === currentUserId) {
          strokes.delete(i);
          return;
        }
      }
    },
    [currentUserId]
  );

  const getSVGPoint = useCallback((e: React.PointerEvent<SVGSVGElement>) => {
    const svg = e.currentTarget;
    const ctm = svg.getScreenCTM();
    if (ctm) {
      const point = new DOMPoint(e.clientX, e.clientY);
      const svgPoint = point.matrixTransform(ctm.inverse());
      return { x: svgPoint.x, y: svgPoint.y };
    }
    const rect = svg.getBoundingClientRect();
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
  }, []);

  const handlePointerDown = useCallback(
    (e: React.PointerEvent<SVGSVGElement>) => {
      if (tool === "eraser") return;
      e.currentTarget.setPointerCapture(e.pointerId);
      const point = getSVGPoint(e);
      const strokeId = `stroke-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
      activeStrokeIdRef.current = strokeId;
      isDrawingRef.current = true;
      lastPointTimeRef.current = Date.now();
      startStroke(point, strokeId);
    },
    [tool, getSVGPoint, startStroke]
  );

  const handlePointerMove = useCallback(
    (e: React.PointerEvent<SVGSVGElement>) => {
      if (!isDrawingRef.current || tool === "eraser") return;
      const now = Date.now();
      if (now - lastPointTimeRef.current < 30) return;
      lastPointTimeRef.current = now;
      const point = getSVGPoint(e);
      const strokeId = activeStrokeIdRef.current;
      if (strokeId) {
        addPoint(point, strokeId);
      }
    },
    [tool, getSVGPoint, addPoint]
  );

  const handlePointerUp = useCallback(() => {
    if (isDrawingRef.current) {
      isDrawingRef.current = false;
      activeStrokeIdRef.current = null;
    }
  }, []);

  // Finalize stroke if tool changes while drawing
  useEffect(() => {
    if (tool === "eraser" && isDrawingRef.current) {
      isDrawingRef.current = false;
      activeStrokeIdRef.current = null;
    }
  }, [tool]);

  const handleStrokePointerDown = useCallback(
    (e: React.PointerEvent<SVGPolylineElement>, strokeId: string) => {
      if (tool === "eraser") {
        e.stopPropagation();
        deleteStrokeById(strokeId);
      }
    },
    [tool, deleteStrokeById]
  );

  const renderStrokes = () => {
    if (!strokes) return null;

    const result = [];
    for (let i = 0; i < strokes.length; i++) {
      const stroke = strokes.get(i);
      if (!stroke) continue;

      const id = stroke.get("id");
      const strokeUserId = stroke.get("userId");
      const strokeColor = stroke.get("color");
      const strokeWidth = stroke.get("width");
      const points = stroke.get("points");

      let pointsStr = "";
      for (let j = 0; j < points.length; j++) {
        const p = points.get(j);
        if (!p) continue;
        if (j > 0) pointsStr += " ";
        pointsStr += `${p.get("x")},${p.get("y")}`;
      }

      result.push(
        <polyline
          key={id}
          data-stroke-id={id}
          data-user-id={strokeUserId}
          points={pointsStr}
          fill="none"
          stroke={strokeColor}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeLinejoin="round"
          pointerEvents={tool === "eraser" ? "stroke" : "none"}
          onPointerDown={(e) => handleStrokePointerDown(e, id)}
          style={{ cursor: tool === "eraser" ? "pointer" : undefined }}
        />
      );
    }
    return result;
  };

  return (
    <div style={{ padding: 16 }}>
      <h1>Collaborative Drawing</h1>
      <p>
        User: <strong data-testid="current-user">{userId}</strong>
      </p>
      <div style={{ display: "flex", gap: 8, marginBottom: 12, alignItems: "center" }}>
        <label>
          Color
          <input
            data-testid="color-picker"
            type="text"
            value={color}
            onChange={(e) => setColor(e.target.value)}
            style={{ marginLeft: 4, width: 96 }}
          />
        </label>
        <label>
          Width
          <input
            data-testid="width-picker"
            type="number"
            min={1}
            max={32}
            value={width}
            onChange={(e) => setWidth(Number(e.target.value))}
            style={{ marginLeft: 4, width: 64 }}
          />
        </label>
        <button
          data-testid="tool-pen"
          onClick={() => setTool("pen")}
          aria-pressed={tool === "pen"}
        >
          Pen
        </button>
        <button
          data-testid="tool-eraser"
          onClick={() => setTool("eraser")}
          aria-pressed={tool === "eraser"}
        >
          Eraser
        </button>
        <button data-testid="undo-mine" onClick={() => undoMyLastStroke()}>
          Undo my last stroke
        </button>
      </div>
      <svg
        data-testid="canvas"
        width={1024}
        height={720}
        viewBox="0 0 1024 720"
        style={{ background: "#fafafa", border: "1px solid #ddd", touchAction: "none" }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        {renderStrokes()}
      </svg>
    </div>
  );
}
```

